import React, { useState, useEffect, useRef } from 'react';
import { ChevronRight, ArrowRight, CheckCircle, ShieldCheck, Lock, AlertTriangle, Star, RefreshCcw } from 'lucide-react';
import { FETISH_DATA } from '../constants';
import { FetishData, TargetAudience } from '../types';

interface Props {
  onComplete: (recommendedFetishId: string, audience: TargetAudience) => void;
  onClose: () => void;
}

type StepType = 'question' | 'text' | 'loading' | 'result';

interface QuizStep {
  type: StepType;
  id?: string;
  title?: string;
  content?: string; // HTML allowed for rich text
  options?: { label: string; value: string; triggerNext?: boolean }[];
  bgImage?: string;
}

const QuizFunnel: React.FC<Props> = ({ onComplete, onClose }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [isAnimating, setIsAnimating] = useState(false);
  const [calculatedFetish, setCalculatedFetish] = useState<FetishData | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  // --- RMBC STRUCTURE DEFINITION ---
  const STEPS: QuizStep[] = [
    // 1. LEAD: Identificar o Problema
    {
      type: 'question',
      id: 'obstacle',
      title: 'Vamos ser honestos...',
      content: 'Qual é o maior obstáculo que te impede de explorar seus desejos mais profundos hoje?',
      options: [
        { label: 'Vergonha ou medo de julgamento', value: 'shame' },
        { label: 'Não sei por onde começar (falta de guia)', value: 'guide' },
        { label: 'Tenho medo de parecer "estranho" ou perigoso', value: 'safety' },
        { label: 'Já tentei, mas foi frustrante/sem graça', value: 'frustration' },
      ]
    },
    // 2. LEAD: Validação Imediata (Micro-sim)
    {
      type: 'text',
      title: 'Eu entendo perfeitamente.',
      content: `
        <p class="mb-4">Muitas pessoas travam exatamente aí. Imagine se existisse uma solução simples que dissolvesse essa barreira em minutos, sem que você precisasse se expor ou gastar horas procurando na internet.</p>
        <p class="text-brand-300 font-bold">Você gostaria de descobrir um método seguro e validado?</p>
      `,
      options: [{ label: 'Sim, quero saber mais', value: 'yes', triggerNext: true }]
    },
    // 3. STORY: Conexão Emocional
    {
      type: 'text',
      title: 'A História da Descoberta',
      content: `
        <p class="mb-4">Oi, aqui é o time KinkMaster. Por anos, vimos pessoas frustradas — sentindo um vazio ou achando que seus desejos eram "errados".</p>
        <p class="mb-4">Livros genéricos não ajudavam. Vídeos explícitos só mostravam a performance, não a conexão. Parecia um beco sem saída.</p>
        <p>Até que descobrimos um padrão: o problema nunca foi o desejo em si, mas a falta de um <strong>mapa seguro</strong>.</p>
      `,
      options: [{ label: 'Continuar...', value: 'next', triggerNext: true }]
    },
    // 4. MUP (Mechanism Underlying Problem): A Causa Real
    {
      type: 'text',
      title: 'A Verdade Surpreendente',
      content: `
        <p class="mb-4">Você sabia que <strong>90% da frustração sexual</strong> vem de tentar adivinhar o que fazer, em vez de seguir um protocolo?</p>
        <p class="mb-4">O bloqueio não é você. São os "mitos culturais" que dizem que o prazer deve ser espontâneo e perfeito. Isso é mentira.</p>
        <p>A verdadeira causa da insegurança é a falta de <strong>Educação Consensual Estruturada</strong>.</p>
      `,
      options: [{ label: 'Faz sentido. Qual a solução?', value: 'next', triggerNext: true }]
    },
    // 5. DIAGNÓSTICO: Mapeamento de Interesse (Para escolher o produto)
    {
      type: 'question',
      id: 'interest',
      title: 'O que faz seu coração acelerar?',
      content: 'Se você pudesse estalar os dedos e dominar uma arte hoje, qual seria?',
      options: [
        { label: 'Explorar a porta de trás (Anal) com segurança', value: 'anal' },
        { label: 'Jogos de Poder, Dominação e Submissão (BDSM)', value: 'bdsm' },
        { label: 'Aventuras com mais pessoas (Ménage/Orgia)', value: 'threesome' },
        { label: 'Adoração e Fetiche por Pés', value: 'podolatria' },
        { label: 'Ser observado ou observar (Voyeur/Exibicionismo)', value: 'voyeur' },
        { label: 'Roleplay e Fantasias (Personagens)', value: 'roleplay' },
      ]
    },
    // 6. DIAGNÓSTICO: Definição de Público (Target Audience)
    {
      type: 'question',
      id: 'audience',
      title: 'Para quem você busca essa jornada?',
      content: 'Isso nos ajuda a personalizar a linguagem do guia.',
      options: [
        { label: 'Sou Homem (ou busco foco masculino)', value: 'Homens' },
        { label: 'Sou Mulher (ou busco foco feminino)', value: 'Mulheres' },
        { label: 'Público Queer / LGBT+ / Fluido', value: 'LGBT+' },
      ]
    },
    // 7. MUS (Mechanism Unique Solution)
    {
      type: 'text',
      title: 'A Solução KinkMaster',
      content: `
        <p class="mb-4">Desenvolvemos o método <strong>R.A.C.K. Progressivo</strong>. Diferente de tudo que você já viu.</p>
        <ul class="text-left space-y-2 mb-4 bg-dark-800 p-4 rounded-lg">
           <li class="flex gap-2"><span class="text-green-500">✓</span> Risco Aceito e Controlado</li>
           <li class="flex gap-2"><span class="text-green-500">✓</span> Narrativas que excitam enquanto ensinam</li>
           <li class="flex gap-2"><span class="text-green-500">✓</span> Zero julgamentos</li>
        </ul>
        <p>Baseado nas suas respostas, nossa IA selecionou o caminho perfeito para você.</p>
      `,
      options: [{ label: 'Ver meu resultado', value: 'next', triggerNext: true }]
    },
    // 8. LOADING
    {
      type: 'loading',
      title: 'Analisando suas respostas...',
      content: 'Cruzando dados com mais de 12 fetiches mapeados...'
    },
    // 9. RESULT (Sales Page)
    {
      type: 'result',
      id: 'result'
    }
  ];

  const handleOptionClick = (value: string) => {
    if (isAnimating) return;

    // Save Answer
    const currentId = STEPS[currentStep].id;
    if (currentId) {
      setAnswers(prev => ({ ...prev, [currentId]: value }));
    }

    // Logic for loading screen
    const nextIndex = currentStep + 1;
    if (STEPS[nextIndex]?.type === 'loading') {
      setCurrentStep(nextIndex);
      // Determine Fetish based on previous answer
      const interest = currentId === 'audience' ? answers['interest'] : value; // Fallback logic
      // Find the mapping (Simplification: Mapping the value directly to ID or fallback)
      let matchedFetish = FETISH_DATA.find(f => f.id === answers['interest']);
      if (!matchedFetish) matchedFetish = FETISH_DATA[0]; // Fallback to Anal

      setCalculatedFetish(matchedFetish);

      setTimeout(() => {
        setCurrentStep(nextIndex + 1); // Go to Result
      }, 2500);
    } else {
      setIsAnimating(true);
      setTimeout(() => {
        setCurrentStep(nextIndex);
        setIsAnimating(false);
        if (scrollRef.current) scrollRef.current.scrollTop = 0;
      }, 300);
    }
  };

  const currentData = STEPS[currentStep];
  const progress = ((currentStep + 1) / STEPS.length) * 100;

  // --- RENDERERS ---

  if (currentData.type === 'loading') {
    return (
      <div className="fixed inset-0 z-[60] bg-dark-900 flex flex-col items-center justify-center p-6 text-center">
        <div className="w-20 h-20 border-4 border-brand-900 border-t-brand-500 rounded-full animate-spin mb-6"></div>
        <h2 className="text-2xl font-bold text-white mb-2 animate-pulse">{currentData.title}</h2>
        <p className="text-gray-400">{currentData.content}</p>
        <div className="mt-8 w-64 h-2 bg-dark-800 rounded-full overflow-hidden">
           <div className="h-full bg-brand-500 animate-[width_2s_ease-in-out_forwards]" style={{width: '0%'}}></div>
        </div>
      </div>
    );
  }

  if (currentData.type === 'result' && calculatedFetish) {
    const audience = (answers['audience'] as TargetAudience) || 'Homens';
    const product = calculatedFetish.products[audience];

    return (
      <div className="fixed inset-0 z-[60] bg-dark-900 overflow-y-auto animate-in fade-in duration-500">
        {/* Sales Page Header */}
        <div className={`w-full h-48 bg-gradient-to-r ${calculatedFetish.color} relative`}>
            <div className="absolute inset-0 bg-black/40"></div>
            <button onClick={onClose} className="absolute top-4 right-4 bg-black/30 p-2 rounded-full text-white hover:bg-black/50"><RefreshCcw size={20}/></button>
            <div className="absolute bottom-0 left-0 w-full p-6 bg-gradient-to-t from-dark-900 to-transparent">
                <span className="bg-brand-500 text-white text-xs font-bold px-2 py-1 rounded mb-2 inline-block">RECOMENDAÇÃO #1</span>
                <h1 className="text-3xl md:text-4xl font-black text-white leading-tight">
                    Seu Perfil: Explorador de {calculatedFetish.title}
                </h1>
            </div>
        </div>

        <div className="max-w-2xl mx-auto p-6 pb-24">
            {/* The Hook/Diagnosis */}
            <div className="bg-dark-800 border border-brand-500/30 rounded-2xl p-6 mb-8 shadow-xl">
                <h2 className="text-xl font-bold text-white mb-4">O que identificamos:</h2>
                <p className="text-gray-300 mb-4">
                    Com base nas suas respostas, você tem uma curiosidade latente sobre <strong>{calculatedFetish.title}</strong>, mas barreiras culturais ou falta de técnica impedem que você viva isso plenamente.
                </p>
                <div className="flex items-start gap-3 bg-brand-900/10 p-4 rounded-lg border border-brand-500/20">
                    <CheckCircle className="text-brand-500 shrink-0 mt-1" size={20} />
                    <div>
                        <strong className="text-brand-200 block">A Boa Notícia:</strong>
                        <span className="text-sm text-gray-400">Você não precisa de anos de prática. Com o guia certo, você pode ter sua primeira experiência segura ainda hoje.</span>
                    </div>
                </div>
            </div>

            {/* The Offer */}
            <h3 className="text-2xl font-bold text-white mb-4 text-center">Apresentando: {product.introTitle}</h3>
            <p className="text-gray-400 text-center mb-8">{product.introDesc}</p>

            <div className="space-y-4 mb-8">
                <div className="flex gap-4 items-center">
                    <div className="w-12 h-12 rounded-full bg-dark-700 flex items-center justify-center shrink-0 font-bold text-xl text-brand-500">1</div>
                    <p className="text-gray-300 text-sm">Passo a passo ilustrado e direto ao ponto.</p>
                </div>
                <div className="flex gap-4 items-center">
                    <div className="w-12 h-12 rounded-full bg-dark-700 flex items-center justify-center shrink-0 font-bold text-xl text-brand-500">2</div>
                    <p className="text-gray-300 text-sm">Scripts de negociação para usar com parceires.</p>
                </div>
                <div className="flex gap-4 items-center">
                    <div className="w-12 h-12 rounded-full bg-dark-700 flex items-center justify-center shrink-0 font-bold text-xl text-brand-500">3</div>
                    <p className="text-gray-300 text-sm">Segurança total baseada no método RACK.</p>
                </div>
            </div>

            {/* Price Anchor */}
            <div className="bg-dark-800 rounded-xl p-6 text-center mb-8 border border-dark-700">
                <p className="text-gray-500 line-through text-sm">Preço normal: R$ 97,00</p>
                <div className="text-4xl font-black text-white mb-2">R$ 47,00</div>
                <p className="text-green-500 text-xs font-bold uppercase tracking-wider mb-4">Oferta Especial Pós-Diagnóstico</p>

                <button 
                    onClick={() => onComplete(calculatedFetish!.id, audience)}
                    className="w-full py-4 bg-brand-600 hover:bg-brand-500 text-white rounded-xl font-bold text-lg shadow-lg shadow-brand-900/40 transition-all flex justify-center items-center gap-2 animate-pulse"
                >
                    Desbloquear Guia Agora <ArrowRight size={20} />
                </button>
                <div className="flex justify-center gap-4 mt-4 text-[10px] text-gray-500">
                    <span className="flex items-center gap-1"><Lock size={10}/> Pagamento Seguro</span>
                    <span className="flex items-center gap-1"><ShieldCheck size={10}/> Garantia de 7 Dias</span>
                </div>
            </div>

            {/* Testimonials */}
            <div className="border-t border-dark-700 pt-8">
                <h4 className="text-white font-bold mb-4 flex items-center gap-2"><Star size={16} className="text-yellow-500 fill-yellow-500"/> O que dizem:</h4>
                <div className="bg-dark-800 p-4 rounded-xl italic text-gray-400 text-sm mb-4">
                    "Eu achava que nunca conseguiria, mas o guia me deu a confiança exata. Minha parceira adorou."
                    <span className="block text-right text-gray-500 not-italic font-bold mt-2">- Membro Anônimo, SP</span>
                </div>
            </div>

             {/* Close / Urgent Warning */}
             <div className="mt-8 p-4 bg-red-900/10 border border-red-900/30 rounded-xl flex gap-3">
                 <AlertTriangle className="text-red-500 shrink-0" />
                 <p className="text-xs text-red-200">
                    <strong>Atenção:</strong> Ignorar seus desejos pode levar à frustração acumulada. Aproveite este momento de clareza para agir.
                 </p>
             </div>
        </div>
      </div>
    );
  }

  // --- RENDER STANDARD STEPS ---

  return (
    <div className="fixed inset-0 z-[60] bg-dark-900 flex flex-col animate-in fade-in zoom-in duration-300">
      {/* Progress Bar */}
      <div className="w-full h-1 bg-dark-800">
        <div 
          className="h-full bg-brand-500 transition-all duration-500 ease-out" 
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="flex-1 overflow-y-auto" ref={scrollRef}>
        <div className="min-h-full flex flex-col items-center justify-center p-6 md:p-12 max-w-2xl mx-auto">

           {/* Close Button (Escape Hatch) */}
           <button onClick={onClose} className="absolute top-4 right-4 text-gray-600 hover:text-gray-400 p-2">
             ✕
           </button>

           <div className={`transition-all duration-300 ${isAnimating ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>

              {/* Title & Content */}
              <h2 className="text-3xl md:text-4xl font-black text-white mb-6 leading-tight">
                  {currentData.title}
              </h2>

              <div 
                className="text-lg md:text-xl text-gray-300 leading-relaxed mb-10 prose prose-invert"
                dangerouslySetInnerHTML={{ __html: currentData.content || '' }}
              />

              {/* Options */}
              <div className="space-y-3 w-full">
                 {currentData.options?.map((opt, idx) => (
                   <button
                     key={idx}
                     onClick={() => handleOptionClick(opt.value)}
                     className="w-full text-left p-5 rounded-2xl bg-dark-800 border border-dark-700 hover:border-brand-500 hover:bg-dark-700 transition-all group flex justify-between items-center shadow-lg"
                   >
                      <span className="font-bold text-gray-200 group-hover:text-white text-base md:text-lg">{opt.label}</span>
                      <ChevronRight className="text-dark-500 group-hover:text-brand-500 transition-colors" />
                   </button>
                 ))}
              </div>

           </div>
        </div>
      </div>
    </div>
  );
};

export default QuizFunnel;

import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { FETISH_DATA } from './constants';
import { FetishData, TargetAudience } from './types';
import ProductFlow from './components/ProductFlow';
import Dashboard from './components/Dashboard';
import CoursePlayer from './components/CoursePlayer';
import SubscriptionModal from './components/SubscriptionModal';
import AuthModal from './components/AuthModal';
import Profile from './components/Profile';
import ClubChat from './components/ClubChat';
import ClubLanding from './components/ClubLanding';
import AdminPanel, { CONST_ADMIN_EMAIL } from './components/AdminPanel';
import CompleteRegistration from './components/CompleteRegistration';
import PublicHome from './components/PublicHome';
import QuizFunnel from './components/QuizFunnel'; // Importado
import { Flame, User, Crown, Home, ShieldAlert, LogOut, Compass } from 'lucide-react';
import { useContentAccess } from './hooks/useContentAccess';

const App: React.FC = () => {
  const { unlockedIds, isSubscribed, unlockContent, userEmail, signOut } = useContentAccess();

  // --- SEGURANÇA ---
  // Verifica se é o admin real baseado no email do hook (que vem do Supabase)
  const isAdmin = userEmail === CONST_ADMIN_EMAIL;

  // Navigation State
  const [view, setView] = useState<'dashboard' | 'player' | 'profile' | 'club' | 'admin' | 'quiz'>('dashboard');

  // Data State
  const [userPreference, setUserPreference] = useState<TargetAudience | null>(null);
  const [loadingProfile, setLoadingProfile] = useState(false);

  // Modals & Flows
  const [selectedLockedFetish, setSelectedLockedFetish] = useState<{data: FetishData, audience: TargetAudience} | null>(null);
  const [currentCourse, setCurrentCourse] = useState<{fetish: FetishData, audience: TargetAudience} | null>(null);
  const [showSubscriptionModal, setShowSubscriptionModal] = useState(false);

  // Auth Modal
  const [authModalState, setAuthModalState] = useState<{ isOpen: boolean; tab: 'login' | 'signup' }>({ 
      isOpen: false, 
      tab: 'login' 
  });

  const [showCompleteRegistration, setShowCompleteRegistration] = useState(false);
  const [showSuccessMessage, setShowSuccessMessage] = useState<string | null>(null);

  // 1. Fetch Profile Preference (Só executa se estiver logado)
  useEffect(() => {
    if (userEmail && supabase) {
        setLoadingProfile(true);
        const checkProfile = async () => {
            const { data } = await supabase
                .from('profiles')
                .select('preference')
                .eq('email', userEmail)
                .single();

            if (data && data.preference) {
                setUserPreference(data.preference as TargetAudience);
                setShowCompleteRegistration(false);
            } else {
                setShowCompleteRegistration(true);
            }
            setLoadingProfile(false);
        };
        checkProfile();
    } else {
        // Se deslogou, limpa estados
        setUserPreference(null);
        setShowCompleteRegistration(false);
    }
  }, [userEmail]);

  // 2. URL Params Handler
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const status = params.get('status');
    const fid = params.get('fid');
    const type = params.get('type');

    if (status === 'success') {
       if (type === 'sub') {
           unlockContent('club', 'sub');
           setShowSuccessMessage("Parabéns! Bem-vindo ao KinkClub.");
       } else if (fid) {
           unlockContent(fid, 'course');
           setShowSuccessMessage("Guia desbloqueado com sucesso!");
       }
       window.history.replaceState({}, document.title, "/");
       setTimeout(() => setShowSuccessMessage(null), 5000);
    }
  }, [unlockContent]);

  // --- RENDERING ---

  // 1. Quiz Público (Gatewall Blindado)
  if (!userEmail) {
    if (view === 'quiz') {
      return (
        <>
          <QuizFunnel 
            onClose={() => setView('dashboard')} 
            onComplete={(fetishId, audience) => {
               // Armazena a intenção e abre o modal de signup
               localStorage.setItem('quiz_intent', JSON.stringify({ fetishId, audience }));
               setAuthModalState({ isOpen: true, tab: 'signup' });
            }} 
          />
          {authModalState.isOpen && (
            <AuthModal 
              initialTab={authModalState.tab} 
              onClose={() => {
                 setAuthModalState({ ...authModalState, isOpen: false });
                 // Se fechou sem cadastro, volta pra home
                 setView('dashboard');
              }} 
            />
          )}
        </>
      );
    }

    return (
      <>
        <PublicHome 
          onLogin={() => setAuthModalState({ isOpen: true, tab: 'login' })}
          onSignup={() => setAuthModalState({ isOpen: true, tab: 'signup' })}
          onStartQuiz={() => setView('quiz')}
        />
        {authModalState.isOpen && (
          <AuthModal 
            initialTab={authModalState.tab} 
            onClose={() => setAuthModalState({ ...authModalState, isOpen: false })} 
          />
        )}
      </>
    );
  }

  // 2. Logado mas sem perfil completo
  if (showCompleteRegistration && !loadingProfile) {
      return (
          <CompleteRegistration 
              userEmail={userEmail}
              onComplete={(pref) => {
                  setUserPreference(pref);
                  setShowCompleteRegistration(false);

                  // Verifica se veio do Quiz
                  const quizIntent = localStorage.getItem('quiz_intent');
                  if (quizIntent) {
                      const { fetishId, audience } = JSON.parse(quizIntent);
                      const fetish = FETISH_DATA.find(f => f.id === fetishId);
                      if (fetish) {
                          setSelectedLockedFetish({ data: fetish, audience });
                          localStorage.removeItem('quiz_intent');
                      }
                  }
              }}
          />
      );
  }

  // 3. Quiz Logado (Overlay)
  if (view === 'quiz') {
      return (
          <QuizFunnel 
              onClose={() => setView('dashboard')}
              onComplete={(fetishId, audience) => {
                  const fetish = FETISH_DATA.find(f => f.id === fetishId);
                  if (fetish) {
                      setSelectedLockedFetish({ data: fetish, audience });
                      setView('dashboard'); // Volta pro dash com o modal aberto
                  }
              }}
          />
      );
  }

  // 4. Logado & Completo -> App Principal
  return (
    <div className="min-h-screen bg-dark-900 text-gray-100 font-sans pb-20 md:pb-0">

      {/* Navbar Desktop */}
      <nav className="border-b border-dark-800 bg-dark-900/95 backdrop-blur sticky top-0 z-40 hidden md:block">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('dashboard')}>
              <Flame className="text-brand-500" />
              <span className="font-bold text-xl tracking-tight">Kink<span className="text-brand-500">Master</span></span>
            </div>

            <div className="flex items-baseline space-x-2">
              <button onClick={() => setView('dashboard')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'dashboard' ? 'text-white bg-dark-800' : 'text-gray-300 hover:text-white hover:bg-dark-700'}`}>Dashboard</button>
              <button onClick={() => setView('club')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'club' ? 'text-brand-400 bg-brand-900/20' : 'text-gray-300 hover:text-brand-400'}`}>Club VIP</button>
              <button onClick={() => setView('profile')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'profile' ? 'text-white bg-dark-800' : 'text-gray-300 hover:text-white hover:bg-dark-700'}`}>Perfil</button>
              <button onClick={() => setView('quiz')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors text-brand-300 border border-brand-500/30 hover:bg-brand-900/20`}>
                  <Compass size={16} className="inline mr-1" /> Quiz
              </button>

              {/* Botão Admin (Só aparece para o email configurado) */}
              {isAdmin && (
                <>
                    <div className="h-6 w-px bg-dark-700 mx-2"></div>
                    <button onClick={() => setView('admin')} className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'admin' ? 'text-red-400 bg-red-900/20' : 'text-gray-300 hover:text-red-400'}`}>
                        <ShieldAlert size={16} className="inline mr-1"/> Admin
                    </button>
                </>
              )}

              <button onClick={signOut} className="ml-4 p-2 text-gray-500 hover:text-white" title="Sair"><LogOut size={18} /></button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Success Toast */}
