                     );
                 })}
             </div>

             {currentQ.allowMultiple && (
                 <button 
                    onClick={() => handleNextStep()}
                    disabled={selectedIndices.length === 0}
                    className="w-full py-5 bg-white hover:bg-gray-100 text-dark-900 rounded-xl font-bold text-lg disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-xl flex items-center justify-center gap-3"
                 >
                    {selectedIndices.length === 0 ? "Selecione uma opção" : "Confirmar e Continuar"} <ArrowRight size={20} />
                 </button>
             )}
         </div>
      </div>
    </div>
  );
};

