  const calculateFinalResult = () => {
    // 1. Calculate Total Points to get percentages
    const totalPoints = Object.values(scores).reduce((a, b) => a + b, 0) || 1; // avoid div by 0

    // 2. Map to array and sort
    const resultsArray = (Object.entries(scores) as [FetishCategory, number][])
