             </div>

             {/* Next Button for Multi-Select */}
             {currentStepData.allowMultiple && (
                <button 
                   onClick={() => handleNext()}
                   disabled={selectedIndices.length === 0}
                   className="mt-10 w-full py-5 bg-white hover:bg-gray-100 text-dark-900 rounded-2xl font-bold text-xl disabled:opacity-30 disabled:cursor-not-allowed transition-all shadow-xl flex items-center justify-center gap-3"
